"import { NextRequest } from 'next/server';
import { prisma } from '@/lib/db';
import { runOrchestrator } from '@/lib/agents/ruflo/orchestrator';

export async function GET(request: NextRequest) {
  const { searchParams } = new URL(request.url);
  const conversationId = searchParams.get('conversationId');
  const userPrompt = searchParams.get('prompt') || '';

  if (!conversationId) {
    return new Response('conversationId is required', { status: 400 });
  }

  const encoder = new TextEncoder();

  // Create stream
  const responseStream = new ReadableStream({
    async start(controller) {
      const sendEvent = (event: any) => {
        controller.enqueue(encoder.encode(`data: ${JSON.stringify(event)}\n\n`));
      };

      try {
        await runOrchestrator(conversationId, userPrompt, (event) => {
          sendEvent(event);
        });
      } catch (err: any) {
        sendEvent({
          type: 'PIPELINE_ERROR',
          message: err.message,
        });
      } finally {
        controller.close();
      }
    },
  });

  return new Response(responseStream, {
    headers: {
      'Content-Type': 'text/event-stream',
      'Cache-Control': 'no-cache, no-transform',
      Connection: 'keep-alive',
    },
  });
}
"

"import { NextRequest, NextResponse } from 'next/server';
import { prisma } from '@/lib/db';

export async function POST(request: NextRequest) {
  try {
    const { conversationId } = await request.json();

    if (!conversationId) {
      return NextResponse.json({ error: 'conversationId is required' }, { status: 400 });
    }

    const conversation = await prisma.conversation.findUnique({
      where: { id: conversationId },
    });

    if (!conversation) {
      return NextResponse.json({ error: 'Conversation not found' }, { status: 404 });
    }

    // Advance stage if paused there
    let nextStage = conversation.currentStage;
    if (conversation.currentStage === 'Architect') {
      nextStage = 'System';
    } else if (conversation.currentStage === 'Queen') {
      nextStage = 'Planner';
    }

    await prisma.conversation.update({
      where: { id: conversationId },
      data: {
        status: 'Active',
        currentStage: nextStage,
      },
    });

    return NextResponse.json({ success: true, nextStage });
  } catch (err: any) {
    return NextResponse.json({ error: err.message }, { status: 500 });
  }
}
"

