import React, { createContext, useContext, useState, useEffect } from 'react';

export interface LogMessage {
  type: string;
  agent?: string;
  message: string;
  data?: any;
  timestamp: string;
}

interface AppContextType {
  activeId: string | null;
  setActiveId: (id: string | null) => void;
  ollamaConnected: boolean;
  checkOllama: () => Promise<boolean>;
  logs: LogMessage[];
  clearLogs: () => void;
  addLog: (log: Omit<LogMessage, 'timestamp'>) => void;
  activePrompt: string;
  setActivePrompt: (prompt: string) => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export function AppProvider({ children }: { children: React.ReactNode }) {
  const [activeId, setActiveId] = useState<string | null>(null);
  const [ollamaConnected, setOllamaConnected] = useState<boolean>(false);
  const [logs, setLogs] = useState<LogMessage[]>([]);
  const [activePrompt, setActivePrompt] = useState<string>('');

  const checkOllama = async () => {
    try {
      const res = await fetch('/api/health');
      if (res.ok) {
        const data = await res.json();
        setOllamaConnected(data.connected);
        return data.connected;
      }
    } catch (e) {
      setOllamaConnected(false);
    }
    return false;
  };

  useEffect(() => {
    checkOllama();
    const interval = setInterval(checkOllama, 10000); // Check every 10s
    return () => clearInterval(interval);
  }, []);

  const clearLogs = () => setLogs([]);

  const addLog = (log: Omit<LogMessage, 'timestamp'>) => {
    setLogs((prev) => [
      ...prev,
      {
        ...log,
        timestamp: new Date().toLocaleTimeString(),
      },
    ]);
  };

  return (
    <AppContext.Provider
      value={{
        activeId,
        setActiveId,
        ollamaConnected,
        checkOllama,
        logs,
        clearLogs,
        addLog,
        activePrompt,
        setActivePrompt,
      }}
    >
      {children}
    </AppContext.Provide
