"import { NextRequest, NextResponse } from 'next/server';
import fs from 'fs';
import path from 'path';

function getFilesRecursively(dir: string, baseDir: string = dir): string[] {
  let results: string[] = [];
  if (!fs.existsSync(dir)) return [];
  const list = fs.readdirSync(dir);
  list.forEach((file) => {
    const filePath = path.join(dir, file);
    const stat = fs.statSync(filePath);
    if (stat && stat.isDirectory()) {
      results = results.concat(getFilesRecursively(filePath, baseDir));
    } else {
      // Normalize to forward slashes for cross-platform compatibility in the UI
      const relative = path.relative(baseDir, filePath).replace(/\\/g, '/');
      results.push(relative);
    }
  });
  return results;
}

export async function GET(
  request: NextRequest,
  context: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await context.params;
    const projectDir = path.join(process.cwd(), 'projects', id);

    if (!fs.existsSync(projectDir)) {
      return NextResponse.json([]);
    }

    const files = getFilesRecursively(projectDir);
    return NextResponse.json(files);
  } catch (err: any) {
    return NextResponse.json({ error: err.message }, { status: 500 });
  }
}
"

"import { NextRequest, NextResponse } from 'next/server';
import fs from 'fs';
import path from 'path';

export async function GET(
  request: NextRequest,
  context: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await context.params;
    const { searchParams } = new URL(request.url);
    const file = searchParams.get('file');

    if (!file) {
      return NextResponse.json({ error: 'file parameter is required' }, { status: 400 });
    }

    const projectDir = path.resolve(process.cwd(), 'projects', id);
    const safePath = path.resolve(projectDir, file);

    // Prevent directory traversal attacks
    if (!safePath.startsWith(projectDir)) {
      return NextResponse.json({ error: 'Forbidden path access' }, { status: 403 });
    }

    if (!fs.existsSync(safePath)) {
      return NextResponse.json({ error: 'File not found' }, { status: 404 });
    }

    const content = fs.readFileSync(safePath, 'utf8');
    return NextResponse.json({ content });
  } catch (err: any) {
    return NextResponse.json({ error: err.message }, { status: 500 });
  }
}
"

