"const { PrismaClient } = require('@prisma/client');
const prisma = new PrismaClient();

async function main() {
  const latestConv = await prisma.conversation.findFirst({
    orderBy: { updatedAt: 'desc' },
    include: { outputs: true }
  });

  if (!latestConv) {
    console.log("No conversations found.");
    return;
  }

  console.log("Conversation ID:", latestConv.id);
  console.log("Conversation Title:", latestConv.title);
  console.log("Conversation Stage:", latestConv.currentStage);

  const archOut = latestConv.outputs.find(o => o.agentName === 'Architect');
  if (archOut) {
    console.log("--- ARCHITECT OUTPUT ---");
    console.log(archOut.validatedJson);
  } else {
    console.log("No Architect output found for this conversation.");
  }
}

main().catch(err => {
  console.error(err);
}).finally(() => {
  prisma.$disconnect();
});
"

