"import { prisma } from './src/lib/db';

async function main() {
  const histories = await prisma.executionHistory.findMany({
    where: {
      logs: {
        contains: 'completed successfully in'
      }
    }
  });

  let realRunsCount = 0;
  let totalDuration = 0;
  let totalTokens = 0;

  histories.forEach((h) => {
    const durationMatch = h.logs.match(/completed successfully in (\d+)ms/i);
    const tokensMatch = h.logs.match(/Estimated tokens: (\d+)/i);

    if (durationMatch) {
      const ms = parseInt(durationMatch[1]);
      // Filter for real runs (> 1s)
      if (ms > 1000) {
        realRunsCount++;
        totalDuration += ms;
        if (tokensMatch) {
          totalTokens += parseInt(tokensMatch[1]);
        }
      }
    }
  });

  console.log("Real runs found (> 1s):", realRunsCount);
  if (realRunsCount > 0) {
    const avgDuration = totalDuration / realRunsCount;
    const avgTps = totalTokens / (totalDuration / 1000);
    console.log("Average Duration (ms):", avgDuration.toFixed(0));
    console.log("Average Tokens:", (totalTokens / realRunsCount).toFixed(0));
    console.log("Average TPS:", avgTps.toFixed(1));
  } else {
    console.log("No real runs found.");
  }
}

main().catch(console.error).finally(() => prisma.$disconnect());
"

