"import fs from 'fs';
import path from 'path';

function getFilesRecursively(dir: string): string[] {
  let results: string[] = [];
  if (!fs.existsSync(dir)) return results;
  const list = fs.readdirSync(dir);
  list.forEach((file) => {
    const filePath = path.join(dir, file);
    const stat = fs.statSync(filePath);
    if (stat && stat.isDirectory()) {
      results = results.concat(getFilesRecursively(filePath));
    } else {
      results.push(filePath);
    }
  });
  return results;
}

const projectDir = path.join(process.cwd(), 'projects', '78502f96-59b2-4839-9b63-99367b58eea0');
console.log("Checking project dir:", projectDir);
const files = getFilesRecursively(projectDir);
console.log("Files on disk count:", files.length);
files.forEach((f) => {
  console.log(` - ${path.relative(projectDir, f)}`);
});
"

