"import { schema } from './src/lib/agents/ruflo/registry/Coder';
import { prisma } from './src/lib/db';
import Ajv from 'ajv';

const ajv = new Ajv({ allErrors: true, strict: false });
const validate = ajv.compile(schema);

async function main() {
  const convId = '78502f96-59b2-4839-9b63-99367b58eea0';
  const out = await prisma.agentOutput.findFirst({
    where: {
      conversationId: convId,
      agentName: 'Coder',
      stage: 'Coder'
    },
    orderBy: { createdAt: 'desc' }
  });

  if (out) {
    console.log("Validating Coder output:");
    console.log(out.validatedJson);
    const parsed = JSON.parse(out.validatedJson);
    const valid = validate(parsed);
    if (!valid) {
      console.log("Schema validation failed with errors:");
      console.log(validate.errors);
    } else {
      console.log("Schema validation succeeded!");
    }
  } else {
    console.log("No Coder output found.");
  }
}

main().catch(console.error).finally(() => prisma.$disconnect());
"

