"import fs from 'fs';
import path from 'path';

function findFilesWithName(dir: string, targetName: string): string[] {
  let results: string[] = [];
  if (!fs.existsSync(dir)) return results;
  const list = fs.readdirSync(dir);
  list.forEach((file) => {
    const filePath = path.join(dir, file);
    const stat = fs.statSync(filePath);
    if (stat && stat.isDirectory()) {
      results = results.concat(findFilesWithName(filePath, targetName));
    } else if (file.toLowerCase() === targetName.toLowerCase()) {
      results.push(filePath);
    }
  });
  return results;
}

const projectsDir = path.join(process.cwd(), 'projects');
console.log("Searching projects dir:", projectsDir);
const matches = findFilesWithName(projectsDir, 'routes.py');
console.log("Matching routes.py files count:", matches.length);
matches.forEach((m) => {
  console.log(`Match: ${m}`);
});
"

