      cache: 'no-store',
      body: JSON.stringify(payload),
      signal: options.timeoutMs ? AbortSignal.timeout(options.timeoutMs) : undefined,
    });

    if (!res.ok) {
      const errText = await res.text();
      throw new Error(`Ollama inference failed: ${res.statusText} - ${errText}`);
