"import { prisma } from './src/lib/db';

async function main() {
  const history = await prisma.executionHistory.findMany({
    where: { conversationId: '634fd90c-5934-4387-95d5-377d60321284' },
    orderBy: { createdAt: 'desc' },
    take: 15
  });

  console.log("Timestamps of failed runs:");
  history.forEach(h => {
    console.log(`${h.createdAt.toISOString()} | Stage: ${h.stage} | Status: ${h.status} | Logs: ${h.logs}`);
  });
}

main().catch(console.error).finally(() => prisma.$disconnect());
"

"async function main() {
  const controller = new AbortController();
  controller.abort();
  try {
    await fetch('http://localhost:11434/api/tags', { signal: controller.signal });
  } catch (err: any) {
    console.log("Type of error:", typeof err);
    console.log("Is error an instance of Error?", err instanceof Error);
    console.log("Error properties:", Object.getOwnPropertyNames(err));
    console.log("Error name:", err.name);
    console.log("Error message:", err.message);
    console.log("Error stringified:", String(err));
  }
}

main().catch(console.error);
"

